/// 未嵌入子集时的占位「豆腐块」字形（16×16）。
pub const tofu_rows: [16]u16 = .{
    0xFFFF, 0x8001, 0x8001, 0x8001, 0x8001, 0x8001, 0x8001, 0x8001,
    0x8001, 0x8001, 0x8001, 0x8001, 0x8001, 0x8001, 0x8001, 0xFFFF,
};

pub fn lookup(cp: u32) ?[16]u16 {
    for (table) |e| {
        if (e.cp == cp) return e.rows;
    }
    return null;
}

/// CJK / 全角标点等：双宽字形（16px）；其它 Unicode 按 8px 占位（位图字体无字形时用 ASCII 替代）。
pub fn isWideCodepoint(cp: u32) bool {
    if (cp >= 0x4E00 and cp <= 0x9FFF) return true;
    if (cp >= 0x3000 and cp <= 0x303F) return true;
    if (cp >= 0xFF00 and cp <= 0xFFEF) return true;
    return false;
}

pub fn codepointWidth(cp: u32) u32 {
    if (cp < 0x80) return 8;
    if (lookup(cp) != null) return 16;
    if (isWideCodepoint(cp)) return 16;
    return 8;
}
